// ──────────────────────────────────────────────
// Look up the social media manager for this client
// and build a Slack DM payload.
// ──────────────────────────────────────────────
// Input (from Execute Workflow Trigger):
//   client_name, linear_issue_url, linear_issue_title, linear_issue_identifier
//
// Expected column in "Clients Info":
//   social_media_manager_slack_id   (Slack user ID, e.g. "U0123ABCD")
//
// Optional columns used if present:
//   social_media_manager_name       (for nicer greeting)
// ──────────────────────────────────────────────

const trigger = $('When Called From MARKET RESEARCH').first().json;
const clients = $('Read Clients Info').all().map(i => i.json);

const clientName = (trigger.client_name || '').trim();
const issueUrl = trigger.linear_issue_url || '';
const issueTitle = trigger.linear_issue_title || 'New Linear issue';
const issueId = trigger.linear_issue_identifier || '';

if (!clientName || !issueUrl) {
  return [{ json: { _skip: true, reason: 'Missing client_name or linear_issue_url' } }];
}

// Case-insensitive match on client_name
const client = clients.find(c =>
  (c.client_name || '').trim().toLowerCase() === clientName.toLowerCase()
);

if (!client) {
  return [{ json: { _skip: true, reason: `No client row found for "${clientName}"` } }];
}

const managerSlackId = (client.social_media_manager_slack_id || '').trim();
if (!managerSlackId) {
  return [{ json: { _skip: true, reason: `No social_media_manager_slack_id set for "${clientName}"` } }];
}

const managerName = (client.social_media_manager_name || '').trim();
const greeting = managerName ? `Hey ${managerName}!` : 'Hey!';

const headerText = issueId
  ? `\u{1F4CB} New Linear issue for ${clientName} (${issueId})`
  : `\u{1F4CB} New Linear issue for ${clientName}`;

const blocks = [
  {
    type: 'header',
    text: { type: 'plain_text', text: headerText, emoji: true }
  },
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `${greeting} A new Linear issue was just created for *${clientName}*.`
    }
  },
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*Title:*\n${issueTitle}`
    }
  },
  {
    type: 'actions',
    elements: [
      {
        type: 'button',
        text: { type: 'plain_text', text: 'Open in Linear', emoji: true },
        url: issueUrl,
        action_id: 'open_linear_issue',
        style: 'primary'
      }
    ]
  }
];

return [{
  json: {
    slack_user_id: managerSlackId,
    client_name: clientName,
    text: `New Linear issue for ${clientName}: ${issueTitle} — ${issueUrl}`,
    blocks: JSON.stringify(blocks)
  }
}];
